#!/usr/bin/env bash
#
# Register `octravpn open-url` as the macOS handler for `oct://` URLs.
#
# Usage:
#   bash dist/macos/install-handler.sh           # install (default)
#   bash dist/macos/install-handler.sh uninstall # remove
#   bash dist/macos/install-handler.sh status    # show LaunchServices state
#
# This script writes a minimal `OctravpnUrlHandler.app` bundle under
# `~/Library/Application Support/octravpn/handler/` whose only job is to
# `exec` the real `octravpn` binary with `open-url <url>`. macOS
# LaunchServices addresses URL handlers by `.app` bundle, not by raw
# binary, so the wrapper is mandatory.
#
# Not run during scaffolding. To test manually:
#
#   1.  cargo build --release -p octravpn-client
#   2.  bash dist/macos/install-handler.sh
#   3.  open "oct://octdeadbeef00000000000000000000000000000000/policy.json"
#   4.  Expect a terminal-style invocation that prints
#       "would open oct://..." (stub behaviour; see open_url.rs).
#
# Read the design doc before changing anything here:
#   docs/oct-url-handler.md
#
# Idempotent: re-running install rewrites the bundle in place.

set -euo pipefail

ACTION="${1:-install}"

# Resolve the workspace root from this script's location. The script
# lives at `<repo>/dist/macos/install-handler.sh`; the binary lands at
# `<repo>/target/release/octravpn` after `cargo build --release`.
SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
OCTRAVPN_BIN="${OCTRAVPN_BIN:-$REPO_ROOT/target/release/octravpn}"

# Use absolute paths everywhere; LaunchServices does not honour $PATH or
# tilde expansion.
HANDLER_ROOT="$HOME/Library/Application Support/octravpn/handler"
APP_BUNDLE="$HANDLER_ROOT/OctravpnUrlHandler.app"
APP_BINARY="$APP_BUNDLE/Contents/MacOS/OctravpnUrlHandler"
APP_PLIST="$APP_BUNDLE/Contents/Info.plist"
APP_BUNDLE_ID="xyz.octra.url-handler"

# `lsregister` is the canonical way to nudge LaunchServices when we
# write a bundle outside `/Applications` and `~/Applications`.
LSREGISTER="/System/Library/Frameworks/CoreServices.framework/Frameworks/LaunchServices.framework/Support/lsregister"

case "$ACTION" in
    install)
        if [ ! -x "$OCTRAVPN_BIN" ]; then
            echo "error: octravpn binary not found at $OCTRAVPN_BIN" >&2
            echo "       run: cargo build --release -p octravpn-client" >&2
            exit 1
        fi

        echo "writing bundle to $APP_BUNDLE"
        rm -rf "$APP_BUNDLE"
        mkdir -p "$APP_BUNDLE/Contents/MacOS"
        mkdir -p "$APP_BUNDLE/Contents/Resources"

        cat > "$APP_BINARY" <<EOF
#!/usr/bin/env bash
# Auto-generated by dist/macos/install-handler.sh. The URL macOS
# dispatches to a URL-handler bundle arrives as the first argv entry.
exec "$OCTRAVPN_BIN" open-url "\$1"
EOF
        chmod +x "$APP_BINARY"

        # Compose a complete Info.plist: bundle metadata plus the
        # URL-types block from octravpn-oct-handler.plist (kept as the
        # source of truth for the URL key block).
        cat > "$APP_PLIST" <<EOF
<?xml version="1.0" encoding="UTF-8"?>
<plist version="1.0">
<dict>
    <key>CFBundleIdentifier</key>
    <string>$APP_BUNDLE_ID</string>
    <key>CFBundleName</key>
    <string>OctravpnUrlHandler</string>
    <key>CFBundleExecutable</key>
    <string>OctravpnUrlHandler</string>
    <key>CFBundlePackageType</key>
    <string>APPL</string>
    <key>CFBundleShortVersionString</key>
    <string>0.1</string>
    <key>CFBundleVersion</key>
    <string>1</string>
    <key>LSUIElement</key>
    <true/>
    <key>CFBundleURLTypes</key>
    <array>
        <dict>
            <key>CFBundleTypeRole</key>
            <string>Viewer</string>
            <key>CFBundleURLName</key>
            <string>xyz.octra.url.oct</string>
            <key>CFBundleURLSchemes</key>
            <array>
                <string>oct</string>
            </array>
            <key>LSHandlerRank</key>
            <string>Default</string>
        </dict>
    </array>
</dict>
</plist>
EOF

        echo "registering with LaunchServices"
        "$LSREGISTER" -f -R -trusted "$APP_BUNDLE"

        echo "verifying registration"
        if "$LSREGISTER" -dump | grep -A2 -i 'bindings:.*oct:' >/dev/null 2>&1; then
            echo "ok: oct: scheme bound (try: open 'oct://octfoo/policy.json')"
        else
            echo "warn: scheme binding not visible in lsregister -dump." >&2
            echo "      Sometimes the cache lags; log out + back in if open(1) doesn't dispatch." >&2
        fi
        ;;

    uninstall)
        if [ -d "$APP_BUNDLE" ]; then
            echo "unregistering and removing $APP_BUNDLE"
            "$LSREGISTER" -u "$APP_BUNDLE" || true
            rm -rf "$APP_BUNDLE"
        else
            echo "nothing to remove at $APP_BUNDLE"
        fi
        ;;

    status)
        if [ -d "$APP_BUNDLE" ]; then
            echo "bundle present: $APP_BUNDLE"
        else
            echo "bundle absent"
        fi
        echo
        echo "current oct: scheme bindings (from lsregister -dump):"
        "$LSREGISTER" -dump | grep -B1 -A3 -i 'oct:' | head -40 || \
            echo "  (none)"
        ;;

    *)
        echo "usage: $0 [install|uninstall|status]" >&2
        exit 64
        ;;
esac
